CREATE VIEW programacion.segundotrimestre AS
 SELECT p_items.id_p_items,
    p_items.id_enlace,
    p_items.id_p_acc,
    p_items.id_partidad_presupuestaria,
    p_items.id_ccnu,
    p_items.id_tip_obra,
    p_items.id_alcance_obra,
    p_items.id_obj_obra,
    p_items.fecha_desde,
    p_items.fecha_hasta,
    p_items.especificacion,
    p_items.id_unidad_medida,
    p_items.cantidad,
    p_items.i,
    p_items.iii,
    p_items.iv,
    p_items.cant_total_distribuir,
    p_items.costo_unitario,
    p_items.precio_total,
    p_items.alicuota_iva,
    p_items.iva_estimado,
    p_items.monto_estimado,
    p_items.est_trim_1,
    p_items.est_trim_2,
    p_items.est_trim_3,
    p_items.est_trim_4,
    p_items.estimado_total_t_acc,
    p_items.estatus_rendi,
    p_items.reprogramado,
    p_items.fecha_reprogramacion,
        CASE
            WHEN ((p_items.ii)::text ~ '^\d+$'::text) THEN (p_items.ii)::integer
            ELSE 0
        END AS ii
   FROM programacion.p_items;


